import React from "react";
import { Link } from "react-router-dom";
import { useNavigate } from 'react-router-dom';

function Nav() {
  // Check if user is logged in
  const isLoggedIn = localStorage.getItem("islogin");

  // Function to handle logout
  const handleLogout = () => {
    // Perform logout actions here, such as removing login status from localStorage
    localStorage.removeItem("islogin");
    // Redirect user to the login page or any other page as desired
    // window.location.href = "/login"; // Example: Redirect to login page
  };

  return (
    <div>
      <nav className="navbar navbar-expand-lg custom_nav-container">
        <a className="navbar-brand" href="/#">
          <img src="images/logo.png" alt="" />
          <span>Petology</span>
        </a>
        <button
          className="navbar-toggler"
          type="button"
          data-toggle="collapse"
          data-target="#navbarSupportedContent"
          aria-controls="navbarSupportedContent"
          aria-expanded="false"
          aria-label="Toggle navigation"
        >
          <span className="navbar-toggler-icon" />
        </button>
        <div className="collapse navbar-collapse" id="navbarSupportedContent">
          <div className="d-flex mx-auto flex-column flex-lg-row align-items-center">
            <ul className="navbar-nav">
              <li className="nav-item active">
                <a className="nav-link" href="/#">
                  Home <span className="sr-only">(current)</span>
                </a>
              </li>
              <li className="nav-item">
                <Link className="nav-link" to="/service">Service</Link>
              </li>
              <li className="nav-item">
                <Link className="nav-link" to="/pet">Pet's Gallery</Link>
              </li>
              <li className="nav-item">
                <Link className="nav-link" to="/clinic">Clinic</Link>
              </li>
              <li className="nav-item">
                <Link className="nav-link" to="/contact">Contact Us</Link>
              </li>
              <li className="nav-item">
                <Link className="nav-link" to="/product">Buy Now</Link>
              </li>
              {/* Render "Cart" link only if user is logged in */}
              {isLoggedIn && (
                <>
                  <li className="nav-item">
                    <Link className="nav-link" to="/cart">Cart</Link>
                  </li>
                  <li className="nav-item">
                    <Link className="nav-link" to="/myorders">My Orders</Link>
                  </li>
                  <li className="nav-item">
                    <button className="nav-link" onClick={handleLogout}>Logout</button>
                  </li>
                </>
              )}
              {/* Render "Login" link if user is not logged in */}
              {!isLoggedIn && (
                <li className="nav-item">
                  <Link className="nav-link" to="/login">Login</Link>
                </li>
              )}
            </ul>
          </div>
        </div>
      </nav>
    </div>
  );
}

export default Nav;
